{
  "artefact_id": "spec-jwt-refresh",
  "owner": "Ruslan Faion <ruslan@faion.net>",
  "version": "1.0.0",
  "last_reviewed": "2026-05-23",
  "feature": "jwt-refresh",
  "status": "Draft",
  "functional_requirements": [
    {"id": "FR-3", "statement": "System SHALL rotate the refresh token on every successful POST /api/v1/auth/refresh."}
  ],
  "non_functional_requirements": [
    {"id": "NFR-2", "statement": "Refresh endpoint p95 latency SHALL be under 200ms at 100 RPS."}
  ],
  "in_scope": ["JWT refresh endpoint", "rotation logic", "tests for rotation"],
  "out_of_scope": ["OAuth federation", "session-based fallback"],
  "success_criteria": ["≥99% successful refresh in production over 7 days", "p95 latency < 200ms"],
  "glossary": {"refresh token": "Long-lived token used to obtain a new short-lived access token via /auth/refresh."}
}

{
  "owner": "team",
  "status": "Accepted",
  "functional_requirements": [{"id": "1", "statement": "system should be nice"}],
  "in_scope": ["everything"],
  "out_of_scope": [],
  "success_criteria": ["users find it useful"],
  "glossary": {}
}
